def validate_routing_logic(routing: dict) -> dict:
    """Validate all segments have complete routing."""
    required_segments = ["hot", "warm", "cold"]
    issues = []

    for segment in required_segments:
        seg_config = routing.get(segment, {})
        if not seg_config:
            issues.append(f"Missing routing for: {segment}")
            continue

        if not seg_config.get("criteria"):
            issues.append(f"{segment}: Missing criteria")
        if not seg_config.get("cta"):
            issues.append(f"{segment}: Missing CTA")
        if not seg_config.get("tags"):
            issues.append(f"{segment}: Missing tags")

    return {
        "passed": len(issues) == 0,
        "issues": issues,
        "segments_defined": len([s for s in required_segments if routing.get(s)])
    }

def validate_landing_page_structure(landing_page: dict) -> dict: """Validate 4-block landing page structure.""" required_blocks = ["hook", "subhead", "value_proposition", "credibility_cta"]
present = [] missing = []
for block in required_blocks: if landing_page.get(block): present.append(block) else: missing.append(block)
# Check CTA friction reducers cta = landing_page.get("credibility_cta", {}) friction_reducers = ["time_estimate", "free_indicator", "instant_results"] missing_friction = [f for f in friction_reducers if not cta.get(f)]
return { "passed": len(missing) == 0 and len(missing_friction) <= 1, "blocks_present": present, "blocks_missing": missing, "friction_reducers_missing": missing_friction, "recommendation": "Add friction reducers to CTA" if missing_friction else None }
